import React, { useEffect, useState } from "react";
import Button from "./ui/Button";
import { useNavigate, useParams } from "react-router-dom";

const BookShow = () => {
  const { id } = useParams();
  const [books, setBooks] = useState([]);
  const navigate = useNavigate();

  useEffect(() => {
    fetch(`http://localhost:3000/api/book/${id}`)
      .then((response) => response.json())
      .then((data) => setBooks(data))
      .catch((error) => console.error("erreur de fetching data ", error));
  }, [id]);

  const handleDelete = () => {
 
    fetch(`http://localhost:3000/api/book/${id}`, {
      method: "DELETE",
      headers: {
        "Content-Type": "application/json",
      },
    })
      .then((response) => {
        if (!response.ok) {
          throw new Error("Erreur lors de la suppression du livre");
        }
        alert("Livre supprimé avec succès !");
        // Recharger la liste ou rediriger si nécessaire
        navigate("/bookList");
      })
      .catch((error) => console.error("erreur de suppretion ", error));

  };

  return (
    <div>
      <div>
        <ul>
          <li>id:{books._id}</li>
          <li>title:{books.title}</li>
          <li>description:{books.description}</li>
          <li>nombre des page:{books.page}</li>
        </ul>
      </div>
      <div className="flex">
        <Button
          className="bg-green-400"
          onClick={() => navigate(`/bookUpdate/${id}`)}
        >
          modifier
        </Button>
        <Button className="bg-red-300" onClick={()=>handleDelete(books.id)}>
          supprimer
        </Button>
      </div>
    </div>
  );
};

export default BookShow;
